var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"윽, 더는 안 닿는 것 같아요.","JPN":"うっ、これ以上は届かないようです。","ENG":"Ugh, it doesn't seem to reach anymore.","TWN":"呃，碰不到了。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"당연한 거지만, 카운터의 능력은 자기 몸에서 멀어질수록 약해져.","JPN":"当たり前だけど、カウンター能力は自分の体から遠ざかるほど弱くなるわ。","ENG":"Naturally, a Counter's ability weakens the farther it is from the body.","TWN":"這是當然的，制裁者的能力離自己身體越遠就越弱。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그리고 네 능력은… 지금 너와 나 사이의 거리가 한계인 모양이네.","JPN":"そしてあなたの能力は……今あなたと私の間の、この距離が限界のようね。","ENG":"And your ability... It seems like the distance between you and me is the limit right now.","TWN":"至於你的能力嘛……看來你和我之間的距離就是你的極限了。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"자신의 한계는 숙지해두는 편이 실전에 도움이 될 거야.","JPN":"自分の限界を知っておくと実践で役に立つわ。","ENG":"Knowing your own limits will help in real situations.","TWN":"了解自己的極限對實戰有幫助。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네!","JPN":"はい！","ENG":"Okay!","TWN":"是的！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 여기서 문제- 네 능력 범위를 벗어난 무장범죄자가 있다면 어떻게 잡아야 할까?","JPN":"では、ここで問題。あなたの能力範囲を越えた位置に武装した犯罪者がいる場合はどうやって捕まえる？","ENG":"Here's a question. What would you do if there's an armed criminal outside your ability's range.","TWN":"那麼問題來了——如果有超出你能力範圍的武裝罪犯，你該如何抓住他呢？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"정답-! 달려가서 거리를 좁혀요!","JPN":"は～い！　走って距離を縮めます！","ENG":"I know! Run and close the distance!","TWN":"快跑過去拉近距離！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"틀린 얘기는 아니네. 하지만 그 범죄자가 너랑 똑같은 속도로 도망친다면 어때?","JPN":"間違ってはいないわね。でもその犯罪者があなたと同じスピードで逃げるとしたら？","ENG":"That's not wrong. But what if the criminal runs away at the same speed as you?","TWN":"說得沒錯。但是如果那個罪犯跑得和你一樣快呢？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그건 치사하네요!","JPN":"それはズルいです！","ENG":"That's unfair!","TWN":"那樣也太卑鄙了！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"싸움이란 건 원래 그렇게 하는 거야. 단순히 더 강한 쪽이 아니라 상황을 더 유리하게 이끄는 쪽이 이기는 거지.","JPN":"戦いとはそういうものなの。単に強い方が勝つのではなく、状況をより有利に持って行った方が勝つ。","ENG":"Fighting is just like that. It's not always about who's stronger, but who can turn the situation in their favor.","TWN":"戰鬥本來就是這樣進行的。勝利的並不僅僅是更強的一方，還是能夠將局勢引向更有利方向的一方。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럴 땐 상대를 도발해봐. 너에게 다가올 수 밖에 없도록.","JPN":"そういう時は相手を挑発してみて。あなたに近づかざるを得ないように。","ENG":"When that happens, try provoking the opponent. Make them have no choice but to approach you.","TWN":"那時就挑釁對手吧，讓他們不得不靠近你。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"도발이 뭔가요?","JPN":"挑発って何ですか？","ENG":"\\"Provoke?\\" What does that mean?","TWN":"挑釁是什麼？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"상대를 기분 나쁘게 하는 거지. 단순히 욕을 하거나 없는 말을 지어내서 자극하는 거야.","JPN":"相手の気を逆撫でるのよ。悪口を言ったり、話を捏造して刺激するの。","ENG":"It means making them upset. Simply insult them or use lies to trigger them.","TWN":"讓對方生氣，用髒話或謊言來刺激對方。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"근처에 범죄자의 동료가 있다면 그 녀석 목숨으로 협박해도 되고.","JPN":"近くに犯罪者の仲間がいる場合は、そいつの命で脅してもいい。","ENG":"If the criminal has an accomplice nearby, you can use that person as leverage to threaten the criminal.","TWN":"如果附近有罪犯的同夥，可以用他的性命來威脅。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그래도 되나요?","JPN":"そんなことしていいんですか？","ENG":"Is that really okay?","TWN":"那樣也可以嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"지금은 너무하다고 생각하겠지만… 겪어보면 알게 될 거야.","JPN":"今は酷いと思うかもしれないけど……実際経験すればわかるようになるよ。","ENG":"It might feel harsh right now, but... you'll understand once you go through it.","TWN":"現在你可能覺得太過分了……但經歷過後你就會明白的。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그렇게 해서라도 이겨야만 한다고 느끼는 때가 올 테니…","JPN":"そうしてでも勝たなければならないと思う時が来るから……","ENG":"There will come a time when you'll feel that winning is the only option, no matter how it happens.","TWN":"總有一天，你會覺得，只要能贏，哪怕用這種方法也無所謂。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"꺄아!!","JPN":"きゃあ！！","ENG":"Kyaaah!!","TWN":"啊！！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"방금 뭐였지?","JPN":"何が起きたの？","ENG":"What was that just now?","TWN":"剛剛那是什麼？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TV3_NPC_NULL_NULL","text":{"KOREA":"우, 운석이다! 저기로 운석 같은 게 떨어졌어!","JPN":"い、隕石だ！　隕石のような物があそこに落ちた！","ENG":"A m-meteorite! Something like a meteorite just fell over there!","TWN":"啊，隕石！那邊掉下來了一個像隕石的東西！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"운석이라고?","JPN":"隕石？","ENG":"A meteorite?","TWN":"隕石？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잠깐… 저 방향은?","JPN":"待って……あの方向は？","ENG":"Wait... that direction is?","TWN":"等等……那個方向？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗, 서윤? 저도 같이 갈래요!","JPN":"あっ、シズカさん？　置いて行かないでください！","ENG":"Seo Yoon! Wait for me!","TWN":"啊，徐芸？我也一起去！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"상황 보고해.","JPN":"状況を報告しろ。","ENG":"Proceed with the status report.","TWN":"報告情況。"},"stage":{"bg":"MYEONGDONG_DAY","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};